/* Base Address for the S-Mode Payload */
OUTPUT_ARCH(riscv)
ENTRY(_start) 

MEMORY
{
  /* OpenSBI 告诉我们 Payload 代码从 0x80200000 开始 */
  /* QEMU virt 平台的 256MB DRAM 结束地址约为 0x8FFFFFFF */
  RAM : ORIGIN = 0x80200000, LENGTH = 0xD000000  
}

/* 定义栈顶符号 */
__stack_top = ORIGIN(RAM) + LENGTH(RAM);

SECTIONS
{
    /* 1. 代码段 (.text) */
    . = ORIGIN(RAM);
    /* .text 段：代码和启动汇编 */
    .text : {
        KEEP(*(.text.init)) /* 确保我们的 _start 函数在最前面 */
        *(.text)
        *(.text.*)
    } > RAM

    /* .rodata 段：只读数据 */
    .rodata : {
        *(.rodata)
        *(.rodata.*)
    } > RAM

    /* .data 段：已初始化的数据 */
    .data : {
        *(.data)
        *(.data.*)
    } > RAM

    /* .bss 段：未初始化的数据 (需要清零) */
    .bss : {
        . = ALIGN(8);
        __bss_start = .; /* 定义 BSS 起始地址符号 */
        *(.bss)
        *(.bss.*)
        . = ALIGN(8);
        __bss_end = .;   /* 定义 BSS 结束地址符号 */
    } > RAM

    /* 栈段：从 RAM 的最高地址向下增长 */
    .stack (NOLOAD): {
        . = ORIGIN(RAM) + 0x100000; 
        __stack_top = .; /* 定义栈顶地址符号 */
    } > RAM

    . = ALIGN(4K);
    . = ORIGIN(RAM) + 0x1000000; 
    PROVIDE(end = .);
}

#include <stdio.h>
#include <sys/stat.h>

int main() {
    struct stat st;

    if (stat("/", &st) < 0) {
        perror("stat");
        return 1;
    }

    printf("mode = %o\n", st.st_mode);
    printf("ino  = %lu\n", (unsigned long)st.st_ino);
    printf("nlink= %lu\n", (unsigned long)st.st_nlink);

    if (S_ISDIR(st.st_mode))
        puts("directory");
    else
        puts("not directory");

    return 0;
}

