    files: Vec<FdResource>,
    pipes: Vec<Pipe>,
}

impl KernelCore {
    fn new(
        &mut self,
        parent_id: Option<usize>,
        pt: usize,
        tf: TrapFrame,
        wd: Path,
    ) -> &mut Process {
        let pid = self.processes.len() + 1;
        let parent = parent_id.map(|p| &kernel_core().processes[p - 1]);
        let files = if let Some(parent) = &parent {
            let files = parent.files.clone();

            for f in files.iter() {
                match &kernel_core().files[f.idx] {
                    FdResource::Stdin => {}
                    FdResource::Stdout => {}
                    FdResource::Stderr => {}
                    FdResource::File(open_file) => {}
                    FdResource::PipeRead(i) => {
                        kernel_core().pipes[*i].readers.push(pid);
                    }
                    FdResource::PipeWrite(i) => {
                        kernel_core().pipes[*i].writers.push(pid);
                    }
                }
            }

            files
        } else {
            let mut files = from_fn(|_|Fd::default());
            files[0].idx = 1;
            files[1].idx = 2;
            files[2].idx = 3;
            files
        };
        self.processes.push(Process {
            state: ProcessState::Ready,
            parent: parent_id,
            pid,
            children: vec![],
            pt,
            tf,
            mmap_base: parent.map(|p| p.mmap_base).unwrap_or(0x20_0000_0000),
            heap_start: parent.map(|p| p.heap_start).unwrap_or(0x10_0000_0000),
            heap_end: parent.map(|p| p.heap_end).unwrap_or(0x10_0000_0000),
            mmaps: parent.map(|p| p.mmaps.clone()).unwrap_or_default(),
            wd,
            files,
            ctx: KernelContext {
                ra: first_run as _,
                sp: STACK_VA,
                // sp: unsafe { KERNEL_STACK.as_mut_ptr() as usize + KERNEL_STACK.len() },
                s0: 0, // place holder
                s1: 0,
                s2: 0,
                s3: 0,
                s4: 0,
                s5: 0,
                s6: 0,
                s7: 0,
                s8: 0,
                s9: 0,
                s10: 0,
                s11: 0,
            },
            programs: parent.map(|p|p.programs.clone()).unwrap_or_default(),
        });

        let p = self.processes.last_mut().unwrap();
        trace!("tf={:X?}", &p.tf);

        p.ctx.s0 = (&p.tf) as *const _ as _;
        trace!("s0={:X}", p.ctx.s0);

        p
    }

    fn schedule(&mut self) {
        let mut i = self.current_process;

        // 往后找
        while i < self.processes.len() {
            trace!("{}.state = {:?}", i, &self.processes[i].state);
            if self.processes[i].state == ProcessState::Ready {
                // 调进去
                self.sched_in(i + 1, "调度器轮询");
                return;
            }
            i += 1;
        }

        // 回过头
        i = 0;
        while i <= self.current_process {
            trace!("{}.state = {:?}", i, &self.processes[i].state);
            if self.processes[i].state == ProcessState::Ready {
                // 调进去
                self.sched_in(i + 1, "调度器轮询");
                return;
            }
            i += 1;
        }

        // 难搞，找不到能调度的进程
        unimplemented!()
    }

    fn sched_in(&mut self, new_pid: usize, reason: &'static str) {
        trace!("准备调度 {}: {reason}", new_pid);
        let c = kernel_core();

        let old = current_process();
        let new = &mut c.processes[new_pid - 1];

        c.current_process = new_pid;
        // 切到 deep_clone 的 satp
        // 取出页表根地址、入口虚拟地址
        let upt = &c.pts[new.pt].pt;
        let root_pa = upt.root_paddr();
        let new_satp = (8usize << 60) | (root_pa.as_usize() >> 12);
        // let user_sp = USER_STACK_VA + PAGE_SIZE_4K;

        new.set_state(ProcessState::Running);
        unsafe {
            if old.pid == new.pid {
                context_reset(&mut new.ctx, new_satp)
            } else {
                context_switch(&mut new.ctx, new_satp, &mut old.ctx)
            }
        };

        // // 保存当前 Context + 切用户页 + 还原目标 Context
        // unsafe {
        //     core::arch::asm!(
        //         "li t6, 1 << 18",
        //         "csrs sstatus, t6",    // SUM=1，允许S态访问U页面

        //         "csrw satp, {user_satp}",
        //         "sfence.vma zero, zero",
        //         user_satp = in(reg) new_satp,
        //         lateout("t6") _,
        //     );
        // };
    }

    fn new_pt(
        &mut self,
        mut pt: PageTable64<Sv39MetaData<VirtAddr>, Rv64PTE, MyPagingHandler>,
    ) -> (
        usize,
        &mut PageTable64<Sv39MetaData<VirtAddr>, Rv64PTE, MyPagingHandler>,
    ) {
        // 分配内核栈
        if pt.query(VirtAddr::from_usize(STACK_VA - 1)).is_err() {
            // 分配内核栈
            map_pages(
                &mut pt.cursor(),
                STACK_VA - STACK_SIZE..STACK_VA,
                MappingFlags::READ | MappingFlags::WRITE | MappingFlags::USER,None
            );
        }

        pt.cursor()
            .map_region(
                memory_addr::VirtAddr::from(DRAM_START),
                |va| memory_addr::PhysAddr::from(va.as_usize()),
                DRAM_END - DRAM_START,
                MappingFlags::READ | MappingFlags::WRITE | MappingFlags::EXECUTE,
                true,
            )
            .unwrap();

        // MMIO 外设区域
        pt.cursor()
            .map_region(
                memory_addr::VirtAddr::from(0x10000000),
                |va| memory_addr::PhysAddr::from(va.as_usize()),
                0xa000,
                MappingFlags::READ | MappingFlags::WRITE,
                true,
            )
            .unwrap();

        self.pts.push(AddressSpace { pt, refcnt: 1 });
        (self.pts.len() - 1, &mut self.pts.last_mut().unwrap().pt)
    }
}

