#[derive(Clone)]
pub struct Path {
    parts: Vec<String>,
}

impl Path {
    fn from_str(r: Option<&Path>, path: &str) -> Self {
        if let Some(r) = r {
            r.clone().join(path)
        } else {
            let parts = path.split('/').map(|p| p.to_string()).collect();
            Self { parts }
        }
    }

    fn join(&self, filename: &str) -> Self {
        let mut parts = if filename.starts_with('/') {
            vec![]
        } else {
            self.parts.clone()
        };

        for part in filename.split("/") {
            if part == "." {
                continue;
            } else if part == ".." {
                parts.pop();
            } else {
                parts.push(part.to_string());
            }
        }
        Self { parts }
    }

    fn to_string(&self) -> String {
        self.parts.join("/")
    }
}

