impl Process {
    fn fd(&self, fd: usize) -> Option<&mut FdResource>  {
        if fd >= self.files.len() {
            return None;
        }
        let idx = self.files[fd].idx;
        if idx == 0 {
            return None;
        }
        Some(&mut kernel_core().files[idx])
    }

    fn file(&self, fd: usize) -> &mut OpenFile {
        let idx = self.files[fd].idx;
        match &mut kernel_core().files[idx] {
            FdResource::File(open_file) => open_file,
            _ => {
                log!("不是文件");
                panic!();
            }
        }
    }

    fn set_state(&mut self, new_state: ProcessState) {
        match self.state {
            ProcessState::Zombie(_) => {}
            _ => {
                self.state = new_state;
            }
        }
    }
}

fn current_process<'a>() -> &'a mut Process {
    match kernel_core()
        .processes
        .get_mut(kernel_core().current_process - 1)
    {
        Some(r) => r,
        None => {
            log!(
                "{} / {}",
                kernel_core().current_process,
                kernel_core().processes.len()
            );
            panic!();
        }
    }
}

