    let mut ptc = pt.cursor();
    // DRAM 区域
    ptc.map_region(
        memory_addr::VirtAddr::from(DRAM_START),
        |va| memory_addr::PhysAddr::from(va.as_usize()),
        DRAM_END - DRAM_START,
        MappingFlags::READ | MappingFlags::WRITE | MappingFlags::EXECUTE,
        true,
    )
    .unwrap();
    // MMIO 外设区域
    ptc.map_region(
        memory_addr::VirtAddr::from(0),
        |va| memory_addr::PhysAddr::from(va.as_usize()),
        DRAM_START,
        MappingFlags::READ | MappingFlags::WRITE,
