    unsafe {
        core::arch::asm!("
        csrw satp, {user_satp}
        sfence.vma zero, zero

        // 内核栈
        mv sp, {kernel_sp}
        csrw sscratch, sp
        // 用户栈
        mv sp, {user_sp}

        // 设置 sepc 准备回用户态
        csrw sepc, {elf_entry} 

        li t0, (1 << 8)
        csrc sstatus, t0
        // 1:SIE S模式中断
        li t0, (1 << 18) | (1 << 1)
        csrs sstatus, t0

        // 外部中断
        li t0, (1 << 9)
        csrs sie, t0

        sret
        ",
            user_sp = in(reg) user_sp,
            kernel_sp = in(reg) kernel_sp,
            elf_entry = in(reg) entry,
            user_satp = in(reg) user_satp,
            options(nostack)
        );
    }
}

