unsafe extern "C" {
    fn __bss_start();
    fn __bss_end();
    fn __stack_top(); // 栈顶地址
    fn __pml4();
}

/// 入口点：负责设置栈和清零 BSS，然后跳转到 kmain
#[unsafe(naked)] // 按照你的要求，将 naked 属性用 unsafe 包裹
#[unsafe(no_mangle)] // 按照你的要求，将 no_mangle 属性用 unsafe 包裹
#[unsafe(link_section = ".text.init")] // 按照你的要求，将 link_section 属性用 unsafe 包裹
pub unsafe extern "C" fn _start() -> ! {
    core::arch::naked_asm!(
        // 1. 设置栈指针 (sp) 到 RAM 的最高地址 (向下增长)
        // la sp, __stack_top (load address)
        "la sp, __stack_top",
        // 2. 清零 BSS 段 (使用 64 位指令 sd 和 8 字节递增)
        // a0 = __bss_start, t1 = __bss_end
        "la t0, __bss_start", // 修复了隐藏的 Unicode 空格
