        "2:",                 // 结束标签 2 (BSS 清零完成)
        // 3. 跳转到 Rust 主函数 kmain
        "call kmain",
        // 4. 理论上 kmain 是一个发散函数 (never returns)，但以防万一
        "j _start",
    )
}

