fn unmap_pages(
    pt: &mut PageTable64Cursor<Sv39MetaData<VirtAddr>, Rv64PTE, MyPagingHandler>,
    mut range: Range<usize>,
) {
    range.start = range.start & !0xfff;
    let page_count = (((range.end + PAGE_SIZE_4K - 1) & !0xfff) - range.start) >> 12;

    trace!("{:X} unmap_pages {:X} ~ {:X}", pt.root_paddr(), range.start, range.end);

    for i in 0..page_count {
        let va_base = memory_addr::VirtAddr::from_usize(range.start + i * PAGE_SIZE_4K);

        if let Ok((pa, _, _)) = pt.query(va_base)
        {
            kernel_core().pager.as_mut().unwrap().free(pa.as_usize(), 0);

            let r = pt.unmap(va_base);
            // r.unwrap();
        }
    }

    // 刷新地址转换缓存
    unsafe {
        asm!("sfence.vma zero, zero");
    }
}

fn read_cstr(mut filename_ptr: *const u8) -> String {
    let mut filename = String::new();
    unsafe {
        while filename_ptr.read() != 0 {
            filename.push(filename_ptr.read() as char);
            filename_ptr = filename_ptr.byte_add(1);
        }
    }
    filename
}

fn read_argv(argv_va: usize) -> Vec<String> {
    let mut result = Vec::new();

    let mut ptr = argv_va as *const usize;

    loop {
        let str_ptr = unsafe { *ptr };

        if str_ptr == 0 {
            break;
        }

        result.push(read_cstr(str_ptr as *const u8));

        ptr = unsafe { ptr.add(1) };
    }

    result
}

