    match tf.trap_kind() {
        TrapKind::UserEcall { num, args } => {
            tf.skip_ecall();
            let op = SyscallOp::from_sys(num, args);
            let ret = dispatch_syscall(tf, op);
            tf.set_ret(ret);
        }
        TrapKind::Breakpoint => {
            log!("breakpoint");
            tf.sepc += 4;
        }

        // 指令缺页
        TrapKind::InstructionPageFault { va } => {
            log!("🚨 Instruction Page Fault");
            log!("fault va = {va:#x}");
            log!("sepc    = {:#x}", tf.sepc);
            // 无实现，死循环挂起内核
            unrecoverable();
        }

        // 加载(读内存)缺页
        TrapKind::LoadPageFault { va } => {
            log!("🚨 Load Page Fault");
            log!("fault va = {va:#x}");
            log!("sepc    = {:#x}", tf.sepc);
            log!("tp      = {:#x}", tf.tp);
            unrecoverable();
        }

        // 存储(写内存)缺页
        TrapKind::StorePageFault { va } => {
            log!("🚨 Store Page Fault");
            log!("fault va = {va:#x}");
            log!("sepc    = {:#x}", tf.sepc);
            log!("sstatus    = {:#x}", tf.sstatus);
            unrecoverable();
        }

        // 非法指令
        TrapKind::IllegalInstruction => {
            log!("🚨 Illegal Instruction");
            log!("sepc = {:#x}", tf.sepc);
            unrecoverable();
        }

        // 未知陷阱，打印完整上下文并挂起
        TrapKind::Unknown { scause, stval } => {
            log!("🚨 [内核 TRAP 崩溃捕获] 🚨");
            log!("scause={:#x}", scause);
            log!("stval ={:#x}", stval);
            log!("sepc  ={:#x}", tf.sepc);
              unrecoverable();
        }
    }
