pub fn spawn_process_with_elf<T: AsRef<str>>(
    uptc: &mut PageTable64Cursor<Sv39MetaData<VirtAddr>, Rv64PTE, MyPagingHandler>,
    raw_elf: &[u8],
    args: &[T],
) -> Result<TrapFrame, SpawnProcessError> {
    let elf = ElfFile::new(&raw_elf).unwrap();

    // free 之前的 program
    let mut programs = vec![];
    swap(&mut current_process().programs, &mut programs);
    for range in programs {
        unmap_pages(uptc, range);
    }

    let mut elf_base = None;

    for ph in elf.program_iter() {
        trace!("{:X?}", ph);

        match ph.get_data(&elf).unwrap() {
            xmas_elf::program::SegmentData::Empty => {},
            xmas_elf::program::SegmentData::Undefined(src) => match ph.get_type().unwrap() {
                Type::Load => {
                    let start = ph.virtual_addr() as usize;
                    if elf_base.is_none() {
                        elf_base = Some(start);
                    }
                    let mem_size = ph.mem_size() as usize;
                    let end: usize = start + mem_size;
                    // trace!("{:X}-{:X}", start, end);

                    // 组装权限：用户态 + 读写，有执行标志追加EXECUTE
                    let mut flags = MappingFlags::USER | MappingFlags::READ | MappingFlags::WRITE;
                    if ph.flags().is_execute() {
                        flags |= MappingFlags::EXECUTE;
                    }

                    current_process().programs.push(start..end);
                    map_pages(uptc, start..end, flags, Some(src));
                }
                _ => {}
            },
            xmas_elf::program::SegmentData::Dynamic32(dynamics) => {},
            xmas_elf::program::SegmentData::Dynamic64(dynamics) => {},
            xmas_elf::program::SegmentData::Note64(note_header, items) => {},
        }
    }

    for sh in elf.section_iter() {
        let sd = sh.get_data(&elf).unwrap();
        match sd {
            SectionData::Rela64(relas) => {
                trace!("{:?}", relas);
            }
            _ => {}
        }

        trace!("{:X?}", sh);
    }

    if uptc.query((USER_STACK_VA - USER_STACK_SIZE).into()).is_err() {
        // 分配一页用户栈
        map_pages(
            uptc,
            USER_STACK_VA - USER_STACK_SIZE..USER_STACK_VA,
            MappingFlags::USER | MappingFlags::READ | MappingFlags::WRITE,None
        );
    }

    let mut sb = UserStackBuilder::new(uptc, USER_STACK_VA);

    // ------------------------
    // 字符串
    // ------------------------

    let ptrs: Vec<_> = args.iter().rev().map(|a| sb.push_cstr(a.as_ref())).collect();

    // ------------------------
    // 对齐
    // ------------------------

    sb.align16();

    // ------------------------
    // auxv
    // ------------------------

    sb.push_usize(0); // AT_NULL value
    sb.push_usize(0); // AT_NULL key

    sb.push_usize(4096); // AT_PAGESZ value
    sb.push_usize(6); // AT_PAGESZ key

    // AT_PHNUM
    let ph_num = elf.header.pt2.ph_count() as usize;
    sb.push_usize(ph_num);
    sb.push_usize(5);

    // AT_PHENT (key=4) 固定56字节
    sb.push_usize(56);
    sb.push_usize(4);

    // AT_PHDR (key=3)
    let ph_off = elf.header.pt2.ph_offset() as usize;
    let at_phdr_val = elf_base.unwrap() + ph_off;
    sb.push_usize(at_phdr_val);
    sb.push_usize(3);


    // ------------------------
    // envp
    // ------------------------

    sb.push_usize(0);

    // ------------------------
    // argv
    // ------------------------

    sb.push_usize(0);

    for addr in ptrs {
        sb.push_usize(addr);
    }

    // ------------------------
    // argc
    // ------------------------

    sb.push_usize(args.len());

    let user_sp = sb.sp;

    trace!("user_sp={:X}", user_sp);

    let entry = elf.header.pt2.entry_point();
    let addr = uptc.query(VirtAddr::from_usize((entry & !0xfff) as _)).unwrap().0;
    trace!("{:X?}", addr);

    let d = unsafe { from_raw_parts(addr.as_usize() as *mut u8, 256) };
    trace!("{:X?}", d);

    let mut tf = TrapFrame::default();
    let entry = elf.header.pt2.entry_point() as usize;
    tf.sepc = entry;
    tf.sp = user_sp;

    tf.sstatus = 
        (1 << 18) // SUM 让内核能访问 USER 页
      | (3 << 13) // 启用浮点
    ;

    unsafe {
        core::arch::asm!("fence.i");
    }

    trace!("{:X?}", tf);

    Ok(tf)
}

pub fn spawn_process<T: AsRef<str>>(
    uptc: &mut PageTable64Cursor<Sv39MetaData<VirtAddr>, Rv64PTE, MyPagingHandler>,
    mut path: &str,
    args: &[T],
) -> Result<TrapFrame, SpawnProcessError> {
    let dev = kernel_core().dev.as_mut().unwrap();
    let fs = kernel_core().fs.as_mut().unwrap();

    let args = if path.ends_with(".sh") {
        let app = "/musl/busybox";
        let mut a = vec![app, "sh", path];
        a.extend(args.iter().map(|a| a.as_ref() as &str));
        path = app;
        a
    } else {
        args.iter().map(|a| a.as_ref() as &str).collect()
    };

    trace!("spawn {} {:?}", path, args);

    let mut elf_file = rsext4::open(dev, fs, path, false)?;
    let r = rsext4::read_at(dev, fs, &mut elf_file, 2 * 1024 * 1024);
    if r.is_err() {
        log!("{:?}", r);
    }
    let raw_data = r.unwrap();
    spawn_process_with_elf(uptc, &raw_data, &args)
}

