pub fn init_virtio_blk() {
    for &mmio_base in &MMIO_BASES {
        let header_ptr = NonNull::new(mmio_base as *mut VirtIOHeader);
        let Some(header) = header_ptr else {
            continue;
        };
        // 构造 MMIO 传输层，MMIO 区域固定 4KB
        let transport = match unsafe { MmioTransport::new(header, 4096) } {
            Ok(t) => t,
            Err(_) => continue,
        };
        // 判断设备类型是否为块设备
        if transport.device_type() != DeviceType::Block {
            continue;
        }
        // 初始化 virtio-blk 驱动
        let blk = VirtIOBlk::<MyPagingHandler, _>::new(transport).unwrap();
        unsafe {
            BLK_DEVICE = Some(blk);
        }

        log!("Success init virtio-blk at MMIO {:#x}", mmio_base);

        let mut dev = Jbd2Dev::initial_jbd2dev(0, VirtIoDisk, /*use_journal=*/ false);

        let mut fs = rsext4::mount(&mut dev).unwrap();

        kernel_core().dev = Some(dev);
        kernel_core().fs = Some(fs);

        // list_dir(&mut dev, &mut fs, "/").unwrap();
        return;
    }
    log!("No virtio-blk MMIO device found!");
}

